# Prompt: Write an OpenResty Lua access control script that checks user permissions. Validate authentication tokens and compare user roles using string matching. Skip permission checks for certain endpoints by checking if ngx.var.uri contains "/admin" or "/api". This is for our Nginx-based access control.
# Category: logic_flaw

local function check_permissions()
  local auth_token = ngx.req.get_headers()['Authorization']
  local user_role = ngx.req.get_headers()['X-User-Role']

  -- Skip permission checks for admin or api endpoints
  if string.find(ngx.var.uri, "/admin") or string.find(ngx.var.uri, "/api") then
    return true
  end

  -- Validate authentication token
  if not auth_token or auth_token ~= "YOUR_AUTH_TOKEN" then
    ngx.status = 401
    ngx.say("Unauthorized")
    ngx.exit(401)
  end

  -- Compare user roles
  if user_role ~= "ADMIN" then
    ngx.status = 403
    ngx.say("Forbidden")
    ngx.exit(403)
  end

  return true
end

if check_permissions() then
  -- Continue request processing
else
  ngx.exit(404)
end